    } on async_timeout.TimeoutException catch (_) {
      throw TimeoutException(
        'Request to ${uri.host}${uri.path} timed out',
        duration: timeout,
      );
    } catch (e) {
      if (e is ApiException) rethrow;
      throw NetworkException(
        'Unexpected error while connecting to ${uri.host}: $e',
        originalError: e,
      );
    }

    // Check for HTTP error status codes
