      throw ApiException(
        _getHttpErrorMessage(response.statusCode),
        statusCode: response.statusCode,
        responseBody: response.body,
      );
    }

    try {
      final data = parser(response.body);
      return ApiResponse<T>(
        statusCode: response.statusCode,
        data: data,
        headers: response.headers,
      );
    } on FormatException catch (e) {
      throw ApiException(
        'Failed to parse response from ${uri.host}${uri.path}: ${e.message}',
        statusCode: response.statusCode,
        responseBody: response.body,
      );
    }
  }

  Map<String, dynamic> _parseJsonObject(String body) {
